@app.route('/upload', methods=['POST'])
def upload_profile_picture():
    if request.method == 'POST' and 'file' in request.files:
        file = request.files['file']
        if file.filename == '':
            return redirect(request.url)
        if file and allowed_extension(file.filename):
            filename = secure_filename(file.filename)
            file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
            return redirect(url_for('show_profile_picture', name=filename))
        else:
            return 'Invalid file type'
    else:
        abort(405)  # Method Not Allowed

@app.route('/<string:name>')
def show_profile_picture(name):
    return send_file(os.path.join(app.config['UPLOAD_FOLDER'], name))

def allowed_extension(filename):
    return set(app.config['ALLOWED_EXTENSIONS']) <= set([filename.rsplit('.', 1)[1].lower()])

